// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {IERC165} from "@openzeppelin/contracts/utils/introspection/IERC165.sol";

/**
 * @title MetadataRegistry
 * @notice Sidecar registry mapping (challengeContract, challengeId) -> metadata URI.
 *
 * Roles:
 *  - owner: can set/overwrite/clear any URI (and batch set).
 *  - challenger: as reported by the challenge contract, can set once (if empty).
 *  - challenge contract itself: may set once on behalf of challenger (if empty).
 *
 * Integration notes:
 *  - The registry is decoupled from any single ChallengePay version.
 *  - It tries `getChallenge(id)` first, and falls back to `challengerOf(id)` if available.
 *  - If neither is present or the call fails, challenger is treated as address(0).
 */
interface IChallengeCore {
    struct ChallengeView {
        uint8 status;
        uint8 outcome;
        address challenger;
        uint8 currency;
        address token;
        uint256 stakeAmount;
        uint256 proposalBond;
        uint256 approvalDeadline;
        uint256 startTs;
        uint8 peerApprovalsNeeded;
        uint16 charityBps;
        address charity;
        uint256 poolSuccess;
        uint256 poolFail;
    }
    function getChallenge(uint256 id) external view returns (ChallengeView memory);
}

interface IChallengeCoreAlt {
    function challengerOf(uint256 id) external view returns (address);
}

// ──────────────────────────────────────────────────────────────────────────────
// Errors
// ──────────────────────────────────────────────────────────────────────────────

error NotOwner();
error ZeroAddress();
error NotChallenger();
error AlreadySet();
error LenMismatch();
error EmptyUri();

/// @notice Public interface for ERC-165 discovery
interface IMetadataRegistry is IERC165 {
    function uri(address challengeContract, uint256 challengeId) external view returns (string memory);
    function hasUri(address challengeContract, uint256 challengeId) external view returns (bool);

    /// @notice Batch get multiple URIs in one call
    function getMany(
        address[] calldata challengeContracts,
        uint256[] calldata challengeIds
    ) external view returns (string[] memory out);

    // Ownership
    function owner() external view returns (address);
    function pendingOwner() external view returns (address);
    function transferOwnership(address newOwner) external;
    function acceptOwnership() external;

    // Owner writes
    function ownerSet(address challengeContract, uint256 challengeId, string calldata newUri) external;
    function ownerSetBatch(address[] calldata challengeContracts, uint256[] calldata challengeIds, string[] calldata uris) external;
    function ownerClear(address challengeContract, uint256 challengeId) external;

    // Challenger/Contract writes
    function challengerSet(address challengeContract, uint256 challengeId, string calldata newUri) external;
    function contractSet(address challengeContract, uint256 challengeId, string calldata newUri) external;
}

contract MetadataRegistry is IMetadataRegistry {
    // ──────────────────────────────────────────────────────────────────────────────
    // Events
    // ──────────────────────────────────────────────────────────────────────────────

    event MetadataSet(
        address indexed challengeContract,
        uint256 indexed challengeId,
        address indexed setter,
        string newUri
    );
    event OwnershipTransferStarted(address indexed previousOwner, address indexed newOwner);
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    // ──────────────────────────────────────────────────────────────────────────────
    // Storage
    // ──────────────────────────────────────────────────────────────────────────────

    address public override owner;
    address public override pendingOwner;

    // challengeContract => challengeId => uri
    mapping(address => mapping(uint256 => string)) private _uri;

    // ──────────────────────────────────────────────────────────────────────────────
    // Modifiers
    // ──────────────────────────────────────────────────────────────────────────────

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    // ──────────────────────────────────────────────────────────────────────────────
    // Constructor
    // ──────────────────────────────────────────────────────────────────────────────

    constructor(address initialOwner) {
        if (initialOwner == address(0)) revert ZeroAddress();
        owner = initialOwner;
        emit OwnershipTransferred(address(0), initialOwner);
    }

    // ──────────────────────────────────────────────────────────────────────────────
    // Ownership (two-step)
    // ──────────────────────────────────────────────────────────────────────────────

    function transferOwnership(address newOwner) external override onlyOwner {
        if (newOwner == address(0)) revert ZeroAddress();
        pendingOwner = newOwner;
        emit OwnershipTransferStarted(owner, newOwner);
    }

    function acceptOwnership() external override {
        if (msg.sender != pendingOwner) revert NotOwner();
        emit OwnershipTransferred(owner, pendingOwner);
        owner = pendingOwner;
        pendingOwner = address(0);
    }

    // ──────────────────────────────────────────────────────────────────────────────
    // Owner writes
    // ──────────────────────────────────────────────────────────────────────────────

    function ownerSet(
        address challengeContract,
        uint256 challengeId,
        string calldata newUri
    ) external override onlyOwner {
        _set(challengeContract, challengeId, newUri);
    }

    function ownerSetBatch(
        address[] calldata challengeContracts,
        uint256[] calldata challengeIds,
        string[] calldata uris
    ) external override onlyOwner {
        uint256 n = challengeContracts.length;
        if (n != challengeIds.length || n != uris.length) revert LenMismatch();
        for (uint256 i = 0; i < n; i++) {
            _set(challengeContracts[i], challengeIds[i], uris[i]);
        }
    }

    function ownerClear(address challengeContract, uint256 challengeId) external override onlyOwner {
        _set(challengeContract, challengeId, "");
    }

    // ──────────────────────────────────────────────────────────────────────────────
    // Challenger / Contract writes (single-shot)
    // ──────────────────────────────────────────────────────────────────────────────

    function challengerSet(
        address challengeContract,
        uint256 challengeId,
        string calldata newUri
        ) external override {
        address ch = _readChallenger(challengeContract, challengeId);
        if (ch == address(0)) revert NotChallenger();
        if (msg.sender != ch) revert NotChallenger();
        if (bytes(_uri[challengeContract][challengeId]).length != 0) revert AlreadySet();
        if (bytes(newUri).length == 0) revert EmptyUri(); // <── added
        _set(challengeContract, challengeId, newUri);
    }

    function contractSet(
        address challengeContract,
        uint256 challengeId,
        string calldata newUri
    ) external override {
        if (msg.sender != challengeContract) revert NotChallenger();
        if (bytes(_uri[challengeContract][challengeId]).length != 0) revert AlreadySet();
        if (bytes(newUri).length == 0) revert EmptyUri(); // <── added
        _set(challengeContract, challengeId, newUri);
    }

    // ──────────────────────────────────────────────────────────────────────────────
    // Views
    // ──────────────────────────────────────────────────────────────────────────────

    function uri(address challengeContract, uint256 challengeId) external view override returns (string memory) {
        return _uri[challengeContract][challengeId];
    }

    function hasUri(address challengeContract, uint256 challengeId) external view override returns (bool) {
        return bytes(_uri[challengeContract][challengeId]).length != 0;
    }

    function getMany(
        address[] calldata challengeContracts,
        uint256[] calldata challengeIds
    ) external view override returns (string[] memory out) {
        uint256 n = challengeContracts.length;
        if (n != challengeIds.length) revert LenMismatch();
        out = new string[](n);
        for (uint256 i = 0; i < n; i++) {
            out[i] = _uri[challengeContracts[i]][challengeIds[i]];
        }
    }

    // ──────────────────────────────────────────────────────────────────────────────
    // Internals
    // ──────────────────────────────────────────────────────────────────────────────

    function _readChallenger(address core, uint256 id) internal view returns (address) {
        if (core == address(0)) return address(0);
        try IChallengeCore(core).getChallenge(id) returns (IChallengeCore.ChallengeView memory cv) {
            return cv.challenger;
        } catch {
            try IChallengeCoreAlt(core).challengerOf(id) returns (address c) {
                return c;
            } catch {
                return address(0);
            }
        }
    }

    function _set(address challengeContract, uint256 challengeId, string memory newUri) internal {
        _uri[challengeContract][challengeId] = newUri;
        emit MetadataSet(challengeContract, challengeId, msg.sender, newUri);
    }

    // ──────────────────────────────────────────────────────────────────────────────
    // ERC-165
    // ──────────────────────────────────────────────────────────────────────────────

    function supportsInterface(bytes4 interfaceId) external pure override returns (bool) {
        return
            interfaceId == type(IERC165).interfaceId ||
            interfaceId == type(IMetadataRegistry).interfaceId;
    }
}

contracts/registry/ChallengeTaskRegistry.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";

contract ChallengeTaskRegistry is Ownable {
    struct Binding {
        uint256 requestId;
        bytes32 taskId;
        bytes32 modelDigest;     // should match AIVM request.modelDigest
        bytes32 paramsHash;      // should match AIVM request.detConfigHash
        bytes32 benchmarkHash;   // optional benchmark/ruleset binding
        uint16 schemaVersion;    // result schema version
        bool exists;
    }

    mapping(address => bool) public dispatchers;
    mapping(uint256 => mapping(address => Binding)) private _bindings;

    event DispatcherSet(address indexed dispatcher, bool allowed);

    event BindingRecorded(
        uint256 indexed challengeId,
        address indexed subject,
        uint256 requestId,
        bytes32 taskId,
        bytes32 modelDigest,
        bytes32 paramsHash,
        bytes32 benchmarkHash,
        uint16 schemaVersion
    );

    event BindingCleared(
        uint256 indexed challengeId,
        address indexed subject
    );

    error NotAuthorized();
    error InvalidSubject();
    error InvalidTask();
    error InvalidRequestId();
    error InvalidModelDigest();
    error InvalidSchemaVersion();

    constructor(address initialOwner) Ownable(initialOwner) {}

    modifier onlyDispatcherOrOwner() {
        if (msg.sender != owner() && !dispatchers[msg.sender]) {
            revert NotAuthorized();
        }
        _;
    }

    function setDispatcher(address dispatcher, bool allowed) external onlyOwner {
        dispatchers[dispatcher] = allowed;
        emit DispatcherSet(dispatcher, allowed);
    }

    function recordBinding(
        uint256 challengeId,
        address subject,
        uint256 requestId,
        bytes32 taskId,
        bytes32 modelDigest,
        bytes32 paramsHash,
        bytes32 benchmarkHash,
        uint16 schemaVersion
    ) external onlyDispatcherOrOwner {
        if (subject == address(0)) revert InvalidSubject();
        if (requestId == 0) revert InvalidRequestId();
        if (taskId == bytes32(0)) revert InvalidTask();
        if (modelDigest == bytes32(0)) revert InvalidModelDigest();
        if (schemaVersion == 0) revert InvalidSchemaVersion();

        _bindings[challengeId][subject] = Binding({
            requestId: requestId,
            taskId: taskId,
            modelDigest: modelDigest,
            paramsHash: paramsHash,
            benchmarkHash: benchmarkHash,
            schemaVersion: schemaVersion,
            exists: true
        });

        emit BindingRecorded(
            challengeId,
            subject,
            requestId,
            taskId,
            modelDigest,
            paramsHash,
            benchmarkHash,
            schemaVersion
        );
    }

    function clearBinding(
        uint256 challengeId,
        address subject
    ) external onlyDispatcherOrOwner {
        delete _bindings[challengeId][subject];
        emit BindingCleared(challengeId, subject);
    }

    function getBinding(
        uint256 challengeId,
        address subject
    )
        external
        view
        returns (
            uint256 requestId,
            bytes32 taskId,
            bytes32 modelDigest,
            bytes32 paramsHash,
            bytes32 benchmarkHash,
            uint16 schemaVersion,
            bool exists
        )
    {
        Binding memory b = _bindings[challengeId][subject];
        return (
            b.requestId,
            b.taskId,
            b.modelDigest,
            b.paramsHash,
            b.benchmarkHash,
            b.schemaVersion,
            b.exists
        );
    }

    function bindingExists(
        uint256 challengeId,
        address subject
    ) external view returns (bool) {
        return _bindings[challengeId][subject].exists;
    }
}

contracts/router/EventChallengeRouter.so.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {IERC165} from "@openzeppelin/contracts/utils/introspection/IERC165.sol";

/**
 * @title EventChallengeRouter
 * @notice Routes multi-outcome events to individual ChallengePay challenges.
 *
 * An "event" (e.g., "Team A vs Team B") maps to N outcomes, each bound to a
 * ChallengePay challenge ID and a subject address. When the event outcome is
 * known, the owner calls `finalizeEvent` which submits the winning proof and
 * finalizes the corresponding challenge on-chain.
 *
 * Admin-only: all mutating functions are restricted to the owner.
 */

interface IChallengePay {
  /// @notice Submit a proof on behalf of a participant (subject).
  function submitProofFor(uint256 id, address participant, bytes calldata proof) external;
  /// @notice Finalize a challenge after the proof/deadline window closes.
  function finalize(uint256 id) external;
}

interface IMetadataRegistry {
  function ownerSet(address contractAddr, uint256 id, string calldata uri) external;
}

error NotOwner();
error EventExists();
error EventMissing();
error AlreadyFinalized();
error BadIndex();
error ZeroAddress();

contract EventChallengeRouter is IERC165 {
  address public owner;
  IChallengePay public immutable challengePay;
  IMetadataRegistry public immutable registry;

  struct Outcome {
    string name;
    uint256 challengeId;
    address subject; // the participant whose proof is submitted on win
  }

  struct EventInfo {
    string title;
    string metaURI;
    bool finalized;
    uint8 winnerIndex;
    Outcome[] outcomes;
  }

  mapping(bytes32 => EventInfo) private events;

  event OwnerChanged(address indexed prev, address indexed next);
  event EventRegistered(bytes32 indexed eventId, string title);
  event OutcomeAdded(bytes32 indexed eventId, uint8 index, string name, uint256 challengeId, address subject);
  event EventURISet(bytes32 indexed eventId, string uri);
  event EventFinalized(bytes32 indexed eventId, uint8 winnerIndex);

  modifier onlyOwner() {
    if (msg.sender != owner) revert NotOwner();
    _;
  }

  constructor(address _challengePay, address _metadataRegistry) {
    if (_challengePay == address(0) || _metadataRegistry == address(0)) revert ZeroAddress();
    owner = msg.sender;
    challengePay = IChallengePay(_challengePay);
    registry = IMetadataRegistry(_metadataRegistry);
    emit OwnerChanged(address(0), msg.sender);
  }

  function transferOwnership(address n) external onlyOwner {
    if (n == address(0)) revert ZeroAddress();
    emit OwnerChanged(owner, n);
    owner = n;
  }

  function registerEvent(bytes32 eventId, string calldata title) external onlyOwner {
    EventInfo storage e = events[eventId];
    if (bytes(e.title).length != 0) revert EventExists();
    e.title = title;
    emit EventRegistered(eventId, title);
  }

  function addOutcome(bytes32 eventId, string calldata name, uint256 challengeId, address subject)
    external
    onlyOwner
  {
    EventInfo storage e = events[eventId];
    if (bytes(e.title).length == 0) revert EventMissing();
    e.outcomes.push(Outcome(name, challengeId, subject));
    emit OutcomeAdded(eventId, uint8(e.outcomes.length - 1), name, challengeId, subject);
  }

  function setEventURI(bytes32 eventId, string calldata uri) external onlyOwner {
    EventInfo storage e = events[eventId];
    if (bytes(e.title).length == 0) revert EventMissing();
    e.metaURI = uri;
    // Best-effort mirror into external metadata registry
    try registry.ownerSet(address(this), uint256(eventId), uri) {} catch {}
    emit EventURISet(eventId, uri);
  }

  /**
   * @notice Finalize an event by declaring the winning outcome.
   * @param eventId  The event identifier.
   * @param winnerIndex  Index into the outcomes array for the winner.
   * @param proof  Proof payload passed to ChallengePay.submitProofFor for the winning subject.
   *
   * Step 1: Submit proof for the winning outcome's subject via submitProofFor.
   *         This is try/catch because the challenge may already have a proof,
   *         the proof window may have closed, or the verifier may reject.
   * Step 2: Finalize the challenge. This will revert if the challenge is not
   *         yet ready to finalize (e.g., proof deadline hasn't passed).
   */
  function finalizeEvent(bytes32 eventId, uint8 winnerIndex, bytes calldata proof) external onlyOwner {
    EventInfo storage e = events[eventId];
    if (bytes(e.title).length == 0) revert EventMissing();
    if (e.finalized) revert AlreadyFinalized();
    if (winnerIndex >= e.outcomes.length) revert BadIndex();

    Outcome storage w = e.outcomes[winnerIndex];

    // Submit proof on behalf of the winning subject
    try challengePay.submitProofFor(w.challengeId, w.subject, proof) {} catch {}

    // Finalize the challenge (determines outcome based on winners)
    challengePay.finalize(w.challengeId);

    e.finalized = true;
    e.winnerIndex = winnerIndex;
    emit EventFinalized(eventId, winnerIndex);
  }

  function getEvent(bytes32 eventId) external view returns (
    string memory title,
    string memory metaURI,
    bool finalized,
    uint8 winnerIndex,
    Outcome[] memory outcomes
  ) {
    EventInfo storage e = events[eventId];
    return (e.title, e.metaURI, e.finalized, e.winnerIndex, e.outcomes);
  }

  function outcomesCount(bytes32 eventId) external view returns (uint256) {
    return events[eventId].outcomes.length;
  }

  // IERC165
  function supportsInterface(bytes4 interfaceId) external pure override returns (bool) {
    return interfaceId == type(IERC165).interfaceId;
  }
}

